import{_ as i,o as a,c as e,ae as u}from"./chunks/framework.RRduUuAx.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/business/chapter-5.md","filePath":"szu/business/chapter-5.md"}'),r={name:"szu/business/chapter-5.md"};function t(o,l,s,n,h,c){return a(),e("div",null,[...l[0]||(l[0]=[u('<h2 id="第一节、市场营销概述" tabindex="-1">第一节、市场营销概述 <a class="header-anchor" href="#第一节、市场营销概述" aria-label="Permalink to &quot;第一节、市场营销概述&quot;">​</a></h2><ol><li>市场营销的含义和原理 <ul><li>含义：市场营销就是在变化的市场环境中，为满足消费需要、实现企业目标而进行的商务活动过程，包括市场调研、选择目标市场、产品开发、产品定价、渠道选择、产品促销、产品储存和运输、产品销售、提供服务等一系列与市场有关的企业业务经营活动。</li><li>原理：市场营销的基本原理是：通过满足顾客需要促进交换，最终实现企业目标。</li></ul></li><li>市场营销过程<br> 是在企业已确定的业务经验范围内，由企业的市场营销部门按照企业总体战略中已规定的任务目标、产品投资组合特点和增长战略模式，从外部环境出发分析、评价各种产品业务增长的市场机会，结合企业的资源状况，综合考虑各项因素后，<strong>选择目标市场、实施市场定位、确定市场营销组合、制定市场营销计划</strong>的完整过程。</li></ol><h2 id="第二节、市场营销过程" tabindex="-1">第二节、市场营销过程 <a class="header-anchor" href="#第二节、市场营销过程" aria-label="Permalink to &quot;第二节、市场营销过程&quot;">​</a></h2><ol><li>市场分析 <ul><li>市场营销环境分析：包括企业的微观环境和宏观环境分析</li><li>市场购买行为分析 <ul><li>1.影响消费者购买行为的因素：经济因素、社会文化因素、个人因素、心里因素</li><li>2.消费者购买决策过程：购买动机的产生、寻找信息、评价方案、决定购买、购后感觉和行为</li><li>3.产业市场购买行为特点</li></ul></li></ul></li><li>市场细分和目标市场选择 <ul><li>市场细分的含义：营销者通过市场调查，依据消费者在需求和欲望、购买行为以及购买习惯等方面的明显差异性，把整个市场划分为若干个子市场的市场分类过程。市场细分的关键是找到影响顾客需求差异的因素，并根据它们来细分市场。</li><li>细分市场的依据：主要通过用户行业、用户规模和用户地理位置等因素作为标准</li><li>目标市场选择<br> 企业选择其目标市场可以采用三种战略：无差异市场营销、差异市场营销和集中市场营销</li><li>市场定位<br> 企业市场定位的全过程包含三个阶段：确认本企业的竞争优势，选择相对竞争优势和明确显示其独特的竞争优势。<br> 竞争优势一般来自两个方面：一是价格竞争优势，二是差异化竞争优势。<br> 市场定位的方法：竞争定位和空白定位。</li></ul></li><li>市场营销调研</li><li>市场营销组合决策 <ul><li>产品决策 <ul><li>1.产品组合决策（扩大产品组合、缩减或淘汰产品组合）</li><li>2.品牌决策</li><li>3.品牌生命周期阶段的营销策略</li></ul></li><li>价格决策 <ul><li>1.营销定价的因素：内部因素（定价目标、产品成本、企业的营销组合）外部因素（市场需求、市场结构、国家政策及其他外部因素）</li><li>2.企业的定价方法：成本导向、需求导向定价、竞争导向定价</li></ul></li><li>渠道决策 <ul><li>1.产品分销渠道及其类型（密集分销、选择分销、独家分销）</li><li>2.分销渠道选择：取决于几个因素（顾客、产品、企业）</li><li>3.中间商类型选择</li></ul></li><li>促销决策 <ul><li>1.促销组合的含义及构成</li><li>2.促销组合决策</li></ul></li></ul></li></ol><h2 id="第三节、网络时代的企业市场营销" tabindex="-1">第三节、网络时代的企业市场营销 <a class="header-anchor" href="#第三节、网络时代的企业市场营销" aria-label="Permalink to &quot;第三节、网络时代的企业市场营销&quot;">​</a></h2><ol><li>网络经济时代企业市场营销方式的转变 <ul><li>网络营销的定义：网络营销是企业整体营销战略的一个组成部分，是建立在互联网基础之上，借助于互联网的特性来实现一定营销目标的一种营销手段。</li><li>网络营销的产生和发展</li></ul></li><li>网络营销与传统营销 <ul><li>网络营销的特点 <ul><li>跨时空、交互性、高效性、经济性、整合性</li></ul></li><li>网络营销对传统营销的冲击 <ul><li>营销营销战略</li><li>营销营销方式</li><li>对传统营销策略的冲击</li></ul></li></ul></li><li>网络营销与传统营销的整合 <ul><li>整合的实质</li><li>整合战略</li></ul></li><li>网络营销的内容和层次 <ul><li>网上宣传</li><li>网上调研</li><li>网络分销联系</li><li>网上直接销售</li><li>网上营销集成</li></ul></li></ol><h2 id="第四节、企业网络营销站点建设和网上市场调查" tabindex="-1">第四节、企业网络营销站点建设和网上市场调查 <a class="header-anchor" href="#第四节、企业网络营销站点建设和网上市场调查" aria-label="Permalink to &quot;第四节、企业网络营销站点建设和网上市场调查&quot;">​</a></h2><ol><li>企业网络营销站点功能</li><li>网络营销战略规划 <ul><li>制定企业建立网站的目标</li><li>确定站点的目标市场</li><li>确定网站提供的信息和服务</li><li>组织站点建设</li></ul></li><li>网络营销站点设计案例 <ul><li>可口可乐网站设计</li><li>宝洁公司</li><li>通用汽车</li></ul></li><li>网上市场调查 <ul><li>概念：是指在互联网上针对特定营销环境进行简单调查设计、收集资料和初步分析的活动。</li><li>特点：互动性、低费用、速度快、客观性、实时检查和监督</li><li>网上市场直接调查</li><li>网上市场简介调查</li></ul></li></ol><h2 id="第五节、网上营销和网络广告" tabindex="-1">第五节、网上营销和网络广告 <a class="header-anchor" href="#第五节、网上营销和网络广告" aria-label="Permalink to &quot;第五节、网上营销和网络广告&quot;">​</a></h2><ol><li>网上销售概念 <ul><li>网上销售渠道的功能</li><li>网上销售渠道的类型</li><li>网上销售的优势</li></ul></li><li>网上交易的过程</li><li>网上售后服务 <ul><li>特点：便捷性、灵活性和个性化、低廉性、直接性</li><li>形式：销售过程的售后服务；网上产品支持和技术服务；推销型售后服务</li><li>网上产品服务网站设计</li></ul></li><li>网络广告的特点和类型</li><li>网络广告的发布</li></ol>',10)])])}const b=i(r,[["render",t]]);export{_ as __pageData,b as default};
